"""Сериализация LLMChatRequest в JSON и обратно."""from __future__ import annotationsimport hashlibimport jsonfrom typing import Anyfrom ..schemas.chat import (    LLMChatMessage,    LLMChatMessageImage,    LLMChatMessageText,    LLMChatReasoningEffort,    LLMChatRequest,    LLMChatResponse,    LLMChatRole,    LLMChatTokensUsage,)def _content_to_dict(content: LLMChatMessageText | LLMChatMessageImage) -> dict[str, Any]:    if isinstance(content, LLMChatMessageText):        return {"type": "text", "text": content.message}    if isinstance(content, LLMChatMessageImage):        return {            "type": "image",            "media_type": content.mime,            "media_content": content.base64,        }    raise TypeError(f"Unexpected content type: {type(content)}")def _content_from_dict(obj: dict[str, Any]) -> LLMChatMessageText | LLMChatMessageImage:    kind = obj.get("type")    if kind == "text":        return LLMChatMessageText(message=obj["text"])    if kind == "image":        return LLMChatMessageImage(            mime=obj["media_type"],            base64=obj["media_content"],        )    raise ValueError(f"Unknown content type: {kind!r}")def _message_to_dict(msg: LLMChatMessage) -> dict[str, Any]:    return {        "role": msg.role.value,        "content": [_content_to_dict(c) for c in msg.content],    }def _message_from_dict(obj: dict[str, Any]) -> LLMChatMessage:    return LLMChatMessage(        role=LLMChatRole(obj["role"]),        content=[_content_from_dict(c) for c in obj["content"]],    )def _request_to_dict(request: LLMChatRequest) -> dict[str, Any]:    return {        "model": request.model,        "messages": [_message_to_dict(m) for m in request.messages],        "provider": request.provider,        "max_tokens": request.max_tokens,        "temperature": request.temperature,        "top_p": request.top_p,        "reasoning": request.reasoning.value,        "stream": request.stream,    }def _request_from_dict(obj: dict[str, Any]) -> LLMChatRequest:    reasoning = obj.get("reasoning", "disabled")    t = obj.get("temperature")    temperature = float(t) if t is not None else 0.0    return LLMChatRequest(        model=obj["model"],        messages=[_message_from_dict(m) for m in obj["messages"]],        provider=obj["provider"],        max_tokens=obj.get("max_tokens", 1024),        top_p=obj.get("top_p"),        reasoning=LLMChatReasoningEffort(reasoning),        temperature=temperature,        stream=obj.get("stream", False),    )def _response_to_dict(response: LLMChatResponse) -> dict[str, Any]:    """LLMChatResponse в словарь для сохранения в кеш."""    message = _message_to_dict(response.message) if response.message else None    tokens_usage = (        {            "prompt": response.tokens_usage.prompt,            "reasoning": response.tokens_usage.reasoning,            "completion": response.tokens_usage.completion,            "total": response.tokens_usage.total,        }        if response.tokens_usage is not None        else None    )    return {        "finish_reason": response.finish_reason,        "created": response.created,        "message": message,        "message_reasoning": response.message_reasoning,        "response_id": response.response_id,        "tokens_usage": tokens_usage,        "cache": response.cache,    }def _response_from_dict(obj: dict[str, Any]) -> LLMChatResponse:    """Словарь из кеша в LLMChatResponse."""    message = _message_from_dict(obj["message"]) if obj.get("message") else None    tu = obj.get("tokens_usage")    tokens_usage = (        LLMChatTokensUsage(            prompt=tu["prompt"],            reasoning=tu["reasoning"],            completion=tu["completion"],            total=tu["total"],        )        if tu        else None    )    return LLMChatResponse(        finish_reason=obj["finish_reason"],        created=obj["created"],        message=message,        message_reasoning=obj.get("message_reasoning", ""),        response_id=obj.get("response_id"),        tokens_usage=tokens_usage,        cache=bool(obj.get("cache", False)),    )class ChatRequestSerializer:    """Статичный сервис: LLMChatRequest ↔ JSON."""    @staticmethod    def to_dict(request: LLMChatRequest) -> dict[str, Any]:        """LLMChatRequest в словарь (тот же формат, что для JSON)."""        return _request_to_dict(request)    @staticmethod    def from_dict(data: dict[str, Any]) -> LLMChatRequest:        """Словарь в LLMChatRequest."""        return _request_from_dict(data)    @staticmethod    def to_json(request: LLMChatRequest, *, ensure_ascii: bool = False) -> str:        """LLMChatRequest в JSON-строку."""        return json.dumps(_request_to_dict(request), ensure_ascii=ensure_ascii)    @staticmethod    def to_json_deterministic(request: LLMChatRequest) -> str:        """Детерминированный JSON (sort_keys=True) для хеширования и кеша."""        return json.dumps(            _request_to_dict(request),            sort_keys=True,            ensure_ascii=False,        )    @staticmethod    def cache_key(request: LLMChatRequest) -> str:        """MD5 от детерминированного JSON запроса — ключ кеша."""        payload = ChatRequestSerializer.to_json_deterministic(request)        return hashlib.md5(payload.encode("utf-8")).hexdigest()    @staticmethod    def from_json(s: str) -> LLMChatRequest:        """JSON-строка в LLMChatRequest."""        return _request_from_dict(json.loads(s))